/// Configuration for security limits across extractors.
///
/// All limits are intentionally conservative to prevent DoS attacks
/// while still supporting legitimate documents.
#[derive(Clone, Default, serde::Serialize, serde::Deserialize)]
#[napi(object, js_name = "SecurityLimits")]
pub struct JsSecurityLimits {
    /// Maximum uncompressed size for archives (500 MB)
    #[napi(js_name = "maxArchiveSize")]
    #[serde(rename = "maxArchiveSize")]
    pub max_archive_size: Option<i64>,
    /// Maximum compression ratio before flagging as potential bomb (100:1)
    #[napi(js_name = "maxCompressionRatio")]
    #[serde(rename = "maxCompressionRatio")]
    pub max_compression_ratio: Option<i64>,
    /// Maximum number of files in archive (10,000)
    #[napi(js_name = "maxFilesInArchive")]
    #[serde(rename = "maxFilesInArchive")]
    pub max_files_in_archive: Option<i64>,
    /// Maximum nesting depth for structures (100)
    #[napi(js_name = "maxNestingDepth")]
    #[serde(rename = "maxNestingDepth")]
    pub max_nesting_depth: Option<i64>,
    /// Maximum length of any single XML entity / attribute / token (1 MiB).
    /// This is a per-token cap, NOT a total cap — billion-laughs class
    /// attacks where a single entity expands to hundreds of MB are caught
    /// here, while normal long text content (a paragraph, a CDATA block) is
    /// caught by `max_content_size` instead.
    #[napi(js_name = "maxEntityLength")]
    #[serde(rename = "maxEntityLength")]
    pub max_entity_length: Option<i64>,
    /// Maximum string growth per document (100 MB)
    #[napi(js_name = "maxContentSize")]
    #[serde(rename = "maxContentSize")]
    pub max_content_size: Option<i64>,
    /// Maximum iterations per operation
    #[napi(js_name = "maxIterations")]
    #[serde(rename = "maxIterations")]
    pub max_iterations: Option<i64>,
    /// Maximum XML depth (100 levels)
    #[napi(js_name = "maxXmlDepth")]
    #[serde(rename = "maxXmlDepth")]
    pub max_xml_depth: Option<i64>,
    /// Maximum cells per table (100,000)
    #[napi(js_name = "maxTableCells")]
    #[serde(rename = "maxTableCells")]
    pub max_table_cells: Option<i64>,
}

#[napi(js_name = "securityLimitsDefault")]
pub fn security_limits_default() -> JsSecurityLimits {
    kreuzberg::SecurityLimits::default().into()
}

