impl From<JsNodeContent> for kreuzberg::NodeContent {
    fn from(val: JsNodeContent) -> Self {
        match val.node_type_tag.as_str() {
            "title" => Self::Title {
                text: val.text.unwrap_or_default(),
            },
            "heading" => Self::Heading {
                level: val.level.unwrap_or_default(),
                text: val.text.unwrap_or_default(),
            },
            "paragraph" => Self::Paragraph {
                text: val.text.unwrap_or_default(),
            },
            "list" => Self::List {
                ordered: val.ordered.unwrap_or_default(),
            },
            "listitem" => Self::ListItem {
                text: val.text.unwrap_or_default(),
            },
            "table" => Self::Table {
                grid: val.grid.map(|v| v.into()).unwrap_or_default(),
            },
            "image" => Self::Image {
                description: val.description,
                image_index: val.image_index,
                src: val.src,
            },
            "code" => Self::Code {
                text: val.text.unwrap_or_default(),
                language: val.language,
            },
            "quote" => Self::Quote,
            "formula" => Self::Formula {
                text: val.text.unwrap_or_default(),
            },
            "footnote" => Self::Footnote {
                text: val.text.unwrap_or_default(),
            },
            "group" => Self::Group {
                label: val.label,
                heading_level: val.heading_level,
                heading_text: val.heading_text,
            },
            "pagebreak" => Self::PageBreak,
            "slide" => Self::Slide {
                number: val.number.unwrap_or_default(),
                title: val.title,
            },
            "definitionlist" => Self::DefinitionList,
            "definitionitem" => Self::DefinitionItem {
                term: val.term.unwrap_or_default(),
                definition: val.definition.unwrap_or_default(),
            },
            "citation" => Self::Citation {
                key: val.key.unwrap_or_default(),
                text: val.text.unwrap_or_default(),
            },
            "admonition" => Self::Admonition {
                kind: val.kind.unwrap_or_default(),
                title: val.title,
            },
            "rawblock" => Self::RawBlock {
                format: val.format.unwrap_or_default(),
                content: val.content.unwrap_or_default(),
            },
            "metadatablock" => Self::MetadataBlock {
                entries: Default::default(),
            },
            _ => Self::Title {
                text: Default::default(),
            },
        }
    }
}

