impl From<JsFormatMetadata> for kreuzberg::FormatMetadata {
    fn from(val: JsFormatMetadata) -> Self {
        match val.format_type_tag.as_str() {
            "pdf" => Self::Pdf(val.pdf.map(|v| v.into()).unwrap_or_default()),
            "docx" => Self::Docx(Box::new(val.docx.map(|v| v.into()).unwrap_or_default())),
            "excel" => Self::Excel(val.excel.map(|v| v.into()).unwrap_or_default()),
            "email" => Self::Email(val.email.map(|v| v.into()).unwrap_or_default()),
            "pptx" => Self::Pptx(val.pptx.map(|v| v.into()).unwrap_or_default()),
            "archive" => Self::Archive(val.archive.map(|v| v.into()).unwrap_or_default()),
            "image" => Self::Image(val.image.map(|v| v.into()).unwrap_or_default()),
            "xml" => Self::Xml(val.xml.map(|v| v.into()).unwrap_or_default()),
            "text" => Self::Text(val.text.map(|v| v.into()).unwrap_or_default()),
            "html" => Self::Html(Box::new(val.html.map(|v| v.into()).unwrap_or_default())),
            "ocr" => Self::Ocr(val.ocr.map(|v| v.into()).unwrap_or_default()),
            "csv" => Self::Csv(val.csv.map(|v| v.into()).unwrap_or_default()),
            "bibtex" => Self::Bibtex(val.bibtex.map(|v| v.into()).unwrap_or_default()),
            "citation" => Self::Citation(val.citation.map(|v| v.into()).unwrap_or_default()),
            "fictionbook" => Self::FictionBook(val.fiction_book.map(|v| v.into()).unwrap_or_default()),
            "dbf" => Self::Dbf(val.dbf.map(|v| v.into()).unwrap_or_default()),
            "jats" => Self::Jats(val.jats.map(|v| v.into()).unwrap_or_default()),
            "epub" => Self::Epub(val.epub.map(|v| v.into()).unwrap_or_default()),
            "pst" => Self::Pst(val.pst.map(|v| v.into()).unwrap_or_default()),
            "code" => Self::Code(Default::default()),
            _ => Self::Pdf(Default::default()),
        }
    }
}

